package router

import (
	"context"
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
	"time"

	"github.com/golang-jwt/jwt/v5"
	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
)

const (
	IdentitySecretName = "picod-router-identity"
	PrivateKeyDataKey  = "private.pem"
	PublicKeyDataKey   = "public.pem"
	KeySize            = 2048
)

type JWTManager struct {
	privateKey *rsa.PrivateKey
	publicKey  *rsa.PublicKey
	clientset  kubernetes.Interface
}

func NewJWTManager() (*JWTManager, error) {
	config, err := rest.InClusterConfig()
	if err != nil {
		klog.Info("Not running in cluster, JWT keys must be provided via environment")
		return &JWTManager{}, nil
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create kubernetes client: %w", err)
	}

	return &JWTManager{
		clientset: clientset,
	}, nil
}

func (jm *JWTManager) GenerateToken(claims map[string]interface{}) (string, error) {
	if jm.privateKey == nil {
		return "", fmt.Errorf("private key not loaded")
	}

	jwtClaims := jwt.MapClaims{}
	for k, v := range claims {
		jwtClaims[k] = v
	}
	jwtClaims["iat"] = time.Now().Unix()
	jwtClaims["exp"] = time.Now().Add(time.Hour).Unix()

	token := jwt.NewWithClaims(jwt.SigningMethodRS256, jwtClaims)
	return token.SignedString(jm.privateKey)
}

func (jm *JWTManager) ValidateToken(tokenString string) (*jwt.Token, error) {
	if jm.publicKey == nil {
		return nil, fmt.Errorf("public key not loaded")
	}

	return jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
		if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
			return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
		}
		return jm.publicKey, nil
	}, jwt.WithExpirationRequired(), jwt.WithIssuedAt(), jwt.WithLeeway(time.Minute))
}

func (jm *JWTManager) TryStoreOrLoadJWTKeySecret(ctx context.Context) error {
	if jm.clientset == nil {
		return jm.loadKeysFromEnv()
	}

	namespace := os.Getenv("AGENTCUBE_NAMESPACE")
	if namespace == "" {
		namespace = "default"
	}

	secret, err := jm.clientset.CoreV1().Secrets(namespace).Get(ctx, IdentitySecretName, metav1.GetOptions{})
	if err != nil {
		if errors.IsNotFound(err) {
			return jm.createKeySecret(ctx, namespace)
		}
		return fmt.Errorf("failed to get identity secret: %w", err)
	}

	return jm.loadKeysFromSecret(secret)
}

func (jm *JWTManager) createKeySecret(ctx context.Context, namespace string) error {
	privateKey, err := rsa.GenerateKey(rand.Reader, KeySize)
	if err != nil {
		return fmt.Errorf("failed to generate private key: %w", err)
	}

	privateKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	})

	publicKeyPEM := pem.EncodeToMemory(&pem.Block{
		Type:  "RSA PUBLIC KEY",
		Bytes: x509.MarshalPKCS1PublicKey(&privateKey.PublicKey),
	})

	secret := &corev1.Secret{
		ObjectMeta: metav1.ObjectMeta{
			Name:      IdentitySecretName,
			Namespace: namespace,
		},
		Type: corev1.SecretTypeOpaque,
		Data: map[string][]byte{
			PrivateKeyDataKey: privateKeyPEM,
			PublicKeyDataKey:  publicKeyPEM,
		},
	}

	_, err = jm.clientset.CoreV1().Secrets(namespace).Create(ctx, secret, metav1.CreateOptions{})
	if err != nil {
		return fmt.Errorf("failed to create identity secret: %w", err)
	}

	jm.privateKey = privateKey
	jm.publicKey = &privateKey.PublicKey
	klog.Infof("Created identity secret %s in namespace %s", IdentitySecretName, namespace)
	return nil
}

func (jm *JWTManager) loadKeysFromSecret(secret *corev1.Secret) error {
	privateKeyPEM, ok := secret.Data[PrivateKeyDataKey]
	if !ok {
		return fmt.Errorf("private key not found in secret")
	}

	publicKeyPEM, ok := secret.Data[PublicKeyDataKey]
	if !ok {
		return fmt.Errorf("public key not found in secret")
	}

	privateKeyBlock, _ := pem.Decode(privateKeyPEM)
	if privateKeyBlock == nil {
		return fmt.Errorf("failed to decode private key PEM")
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(privateKeyBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	publicKeyBlock, _ := pem.Decode(publicKeyPEM)
	if publicKeyBlock == nil {
		return fmt.Errorf("failed to decode public key PEM")
	}

	publicKey, err := x509.ParsePKCS1PublicKey(publicKeyBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	jm.privateKey = privateKey
	jm.publicKey = publicKey
	klog.Info("Loaded JWT keys from secret")
	return nil
}

func (jm *JWTManager) loadKeysFromEnv() error {
	privateKeyPEM := os.Getenv("PICOD_AUTH_PRIVATE_KEY")
	publicKeyPEM := os.Getenv("PICOD_AUTH_PUBLIC_KEY")

	if privateKeyPEM == "" || publicKeyPEM == "" {
		return fmt.Errorf("PICOD_AUTH_PRIVATE_KEY and PICOD_AUTH_PUBLIC_KEY must be set when not running in cluster")
	}

	privateKeyBlock, _ := pem.Decode([]byte(privateKeyPEM))
	if privateKeyBlock == nil {
		return fmt.Errorf("failed to decode private key PEM from env")
	}

	privateKey, err := x509.ParsePKCS1PrivateKey(privateKeyBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse private key: %w", err)
	}

	publicKeyBlock, _ := pem.Decode([]byte(publicKeyPEM))
	if publicKeyBlock == nil {
		return fmt.Errorf("failed to decode public key PEM from env")
	}

	publicKey, err := x509.ParsePKCS1PublicKey(publicKeyBlock.Bytes)
	if err != nil {
		return fmt.Errorf("failed to parse public key: %w", err)
	}

	jm.privateKey = privateKey
	jm.publicKey = publicKey
	klog.Info("Loaded JWT keys from environment")
	return nil
}

func (jm *JWTManager) GetPublicKey() *rsa.PublicKey {
	return jm.publicKey
}

